```class Solution {
public:
    int nextBeautifulNumber(int n) {
        int count[10] = {0}; // array to store digit count
        int result = n + 1; // initialize result with n+1
        while (result > 0) {
            int digit = result % 10; // get the last digit
            count[digit]++; // increment count of the last digit
            result /= 10; // remove the last digit from the number
        }
        for (int i = 1; i <= 9; i++) { // iterate through digits from 1 to 9
            if (count[i] > 0 && count[i] == count[i + 1]) { // check if the count of i is greater than 0 and equal to i+1
                result = i * (count[i] + 1); // update result with i * (count[i] + 1)
                count[i] = 0; // reset count of i
            }
        }
        return result;
    }
};
```

